{
  "guidedPractice": {
    "title": "Guided Practice: Motor Performance Check",
    "objective": "Guide the learner through selecting the correct instruments for voltage, current, and energy consumption in a motor circuit.",
    "retrievalTextLines": [
      "Scenario: You are checking a workshop motor. You need to verify the electrical pressure (voltage), the flow of electricity (current), and the total electricity consumed over a 4-hour shift.",
      "Step 1: Identify the instrument for electrical pressure. To check the 'push' or potential difference at the motor terminals, select a Voltmeter.",
      "Step 2: Identify the instrument for current flow. To measure the flow of electricity through the circuit, select an Ammeter.",
      "Step 3: Identify the instrument for total consumption. To record the total usage over a period of time (4 hours), select an Energy Meter."
    ],
    "questionText": "Based on the scenario above, list the three specific instruments required to measure the electrical pressure, the flow of electricity, and the total consumption over the 4-hour shift, in that order.",
    "answerGuidance": [
      "Voltmeter, Ammeter, Energy Meter",
      "Voltmeter, Ammeter, and Energy Meter"
    ],
    "hint": "Think: Pressure = Volts, Flow = Amps, Total usage over time = Energy."
  },
  "practice": {
    "title": "Practice: Component Testing",
    "objective": "Assess the learner's ability to match resistance and instantaneous power to their respective measuring instruments.",
    "retrievalTextLines": [
      "Recall that different instruments are used depending on whether you are measuring a static property like resistance or a dynamic property like the rate of work (power)."
    ],
    "questionText": "A technician needs to measure the electrical resistance of a disconnected heating element and then measure the instantaneous power the element draws the moment it is switched on. Name the two specific instruments required for these two tasks.",
    "answerGuidance": [
      "Ohmmeter and Wattmeter",
      "Ohmmeter, Wattmeter"
    ],
    "hint": "Remember that an Ohmmeter is for resistance and a Wattmeter measures the 'work rate' or instantaneous power."
  }
}

{
